// US exchange-listed universe (NASDAQ Trader Symbol Directory).
// Regenerate: npm run gen:universe (filters ETFs, test issues, obvious units/warrants).
// Static numeric fields derived deterministically for stable UI; live quote from backend.

import RAW from "./stock-universe-data.json";

// Deterministic pseudo-random in [0,1) seeded from string
function hash(s) {
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return ((h >>> 0) % 100000) / 100000;
}
function fmtBig(n) {
  if (n >= 1e12) return `${(n / 1e12).toFixed(2)}T`;
  if (n >= 1e9) return `${(n / 1e9).toFixed(2)}B`;
  if (n >= 1e6) return `${(n / 1e6).toFixed(2)}M`;
  return n.toFixed(0);
}
export const STOCK_UNIVERSE = RAW.map(r => {
  const a = hash(r.sym);
  const b = hash(r.sym + "x");
  const c = hash(r.sym + "y");
  const price = 20 + a * 600;
  const chg = -5 + b * 10;
  const volM = 1 + c * 200;
  const mktCapNum = 1e9 + a * 3e12;
  const pe = 8 + b * 90;
  const eps = 0.5 + c * 25;
  const epsGrowth = -40 + a * 200;
  return {
    sym: r.sym,
    name: r.name,
    sector: r.sector,
    price,
    chg,
    vol: `${volM.toFixed(2)}M`,
    relVol: 0.4 + b * 1.4,
    mktCap: fmtBig(mktCapNum),
    pe,
    eps,
    epsGrowth,
  };
});
